('about', 'stats', '{"items":[{"value":"50K+","label":"تأشيرة تم إصدارها","label_en":"Visas Issued","icon":"Award"},{"value":"98%","label":"نسبة الموافقة","label_en":"Approval Rate","icon":"CheckCircle2"},{"value":"150+","label":"دولة نخدمها","label_en":"Countries Served","icon":"Globe"},{"value":"24/7","label":"دعم متواصل","label_en":"Support Available","icon":"Clock"}]}'::jsonb, 2),
('about', 'story', '{"badge":"قصتنا","badge_en":"Our Story","title":"رحلة نجاح مستمرة","title_en":"A Continuous Success Journey","paragraphs":["بدأت عطلات رحلاتكم رحلتها في عام 2015 كمكتب صغير لخدمات التأشيرات في الرياض. ومنذ ذلك الحين، نمت الشركة لتصبح واحدة من أكبر شركات خدمات التأشيرات في المنطقة.","نفخر بفريقنا المكون من أكثر من 50 متخصصاً في التأشيرات والسفر، يعملون على مدار الساعة لضمان حصول عملائنا على أفضل خدمة ممكنة.","هدفنا هو جعل عملية الحصول على التأشيرة سهلة وخالية من المتاعب، حتى تتمكن من التركيز على الاستمتاع برحلتك."],"paragraphs_en":["Otolat Rahlatcom started its journey in 2015 as a small visa services office in Riyadh. Since then, the company has grown to become one of the largest visa services companies in the region.","We are proud of our team of over 50 visa and travel specialists, working around the clock to ensure our clients receive the best possible service.","Our goal is to make the visa application process easy and hassle-free, so you can focus on enjoying your trip."],"image":"https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=600&h=400&fit=crop","years_value":"10+","years_label":"سنوات خبرة","years_label_en":"Years Experience"}'::jsonb, 3),
