('faq', 'hero', '{"title":"الأسئلة الشائعة","title_en":"Frequently Asked Questions","description":"ابحث عن إجابات لأسئلتك الأكثر شيوعاً حول خدماتنا","description_en":"Find answers to the most common questions about our services"}'::jsonb, 1),
('faq', 'categories', '{"items":[{"icon":"FileText","title":"التقديم على التأشيرة","title_en":"Visa Application","questions":[{"question":"كيف يمكنني التقديم على تأشيرة؟","question_en":"How can I apply for a visa?","answer":"يمكنك التقديم على التأشيرة عبر موقعنا الإلكتروني. اختر الدولة المطلوبة، ثم اتبع خطوات التقديم وقم برفع المستندات المطلوبة وأكمل عملية الدفع.","answer_en":"You can apply for a visa through our website. Select the desired country, follow the application steps, upload required documents, and complete the payment."},{"question":"ما هي المستندات المطلوبة للتقديم؟","question_en":"What documents are required for the application?","answer":"تختلف المستندات المطلوبة حسب نوع التأشيرة والدولة. بشكل عام، ستحتاج إلى: جواز سفر ساري، صور شخصية، كشف حساب بنكي، حجز فندقي، وتذاكر سفر.","answer_en":"Required documents vary by visa type and country. Generally, you will need: valid passport, personal photos, bank statement, hotel booking, and travel tickets."},{"question":"هل يمكنني التقديم لأكثر من شخص في طلب واحد؟","question_en":"Can I apply for multiple people in one application?","answer":"نعم، يمكنك التقديم لعدة أشخاص في طلب واحد. أثناء التقديم، حدد عدد المسافرين البالغين والأطفال والرضع.","answer_en":"Yes, you can apply for multiple people in one application. During the application, specify the number of adults, children, and infants."}]},{"icon":"Clock","title":"مدة المعالجة","title_en":"Processing Time","questions":[{"question":"كم تستغرق مدة معالجة التأشيرة؟","question_en":"How long does visa processing take?","answer":"تختلف مدة المعالجة حسب نوع التأشيرة والدولة. عادةً تتراوح بين 3-15 يوم عمل.","answer_en":"Processing time varies by visa type and country. Usually ranges from 3-15 business days."},{"question":"هل يمكن تسريع معالجة الطلب؟","question_en":"Can the application processing be expedited?","answer":"نعم، نوفر خدمة المعالجة السريعة لبعض التأشيرات مقابل رسوم إضافية.","answer_en":"Yes, we offer express processing for some visas for an additional fee."},{"question":"كيف يمكنني متابعة حالة طلبي؟","question_en":"How can I track my application status?","answer":"يمكنك متابعة حالة طلبك من خلال صفحة تتبع الطلب على موقعنا.","answer_en":"You can track your application status through the Track Application page on our website."}]},{"icon":"CreditCard","title":"الدفع والأسعار","title_en":"Payment & Pricing","questions":[{"question":"ما هي طرق الدفع المتاحة؟","question_en":"What payment methods are available?","answer":"نقبل الدفع عبر: البطاقات الائتمانية (فيزا، ماستركارد)، Apple Pay، مدى، والتحويل البنكي.","answer_en":"We accept: credit cards (Visa, Mastercard), Apple Pay, Mada, and bank transfer."},{"question":"هل الأسعار شاملة رسوم التأشيرة الحكومية؟","question_en":"Do prices include government visa fees?","answer":"يختلف ذلك حسب نوع التأشيرة. يتم توضيح ذلك بوضوح في صفحة كل تأشيرة.","answer_en":"This varies by visa type. This is clearly indicated on each visa page."},{"question":"هل يمكنني استرداد المبلغ إذا تم رفض التأشيرة؟","question_en":"Can I get a refund if my visa is rejected?","answer":"رسوم الخدمة غير قابلة للاسترداد. راجع سياسة الاسترجاع للتفاصيل.","answer_en":"Service fees are non-refundable. See our refund policy for details."}]},{"icon":"Shield","title":"الأمان والخصوصية","title_en":"Security & Privacy","questions":[{"question":"هل معلوماتي الشخصية آمنة؟","question_en":"Is my personal information secure?","answer":"نعم، نستخدم أعلى معايير التشفير والأمان لحماية بياناتك.","answer_en":"Yes, we use the highest encryption and security standards to protect your data."},{"question":"كيف يتم التعامل مع مستنداتي؟","question_en":"How are my documents handled?","answer":"يتم تخزين مستنداتك بشكل آمن ومشفر. نحتفظ بها فقط للمدة اللازمة لمعالجة طلبك.","answer_en":"Your documents are stored securely and encrypted. We keep them only for the time needed to process your application."}]},{"icon":"Globe","title":"عام","title_en":"General","questions":[{"question":"هل أنتم مكتب رسمي معتمد؟","question_en":"Are you an officially licensed office?","answer":"نعم، نحن مكتب مرخص ومعتمد من الجهات المختصة.","answer_en":"Yes, we are a licensed and authorized office."},{"question":"كيف يمكنني التواصل معكم؟","question_en":"How can I contact you?","answer":"يمكنك التواصل معنا عبر الهاتف، البريد الإلكتروني، واتساب، أو زيارة مكتبنا.","answer_en":"You can contact us via phone, email, WhatsApp, or visit our office."}]}]}'::jsonb, 2),

